diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index f9155cc66031..15081ff13c6a 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2263,6 +2263,65 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
     return CallInst::Create(F, {Op0, Z});
   }

+  // sub(smin(add_nsw(X, 1), Y), smin(X, Y)) --> select (X < Y), 1, 0
+  // sub(umin(add_nuw(X, 1), Y), umin(X, Y)) --> select (X < Y), 1, 0
+  // sub(smin(or_disjoint(X, 1), Y), smin(X, Y)) --> select (X < Y), 1, 0
+  // sub(umin(or_disjoint(X, 1), Y), umin(X, Y)) --> select (X < Y), 1, 0
+  if (auto *Op0MinMax = dyn_cast<MinMaxIntrinsic>(Op0)) {
+    Intrinsic::ID IID = MinMax->getIntrinsicID();
+    if (Op0MinMax->getIntrinsicID() == IID && Op0MinMax->hasOneUse() ||
+        Op1->hasOneUse()) {
+      Value *X = MinMax->getLHS(), *Y = MinMax->getRHS();
+      Value *M1LHS = Op0MinMax->getLHS(), *M1RHS = Op0MinMax->getRHS();
+
+      // The add operand should be min(add_nsw/nuw(X, 1), Y)
+      // or min(Y, add_nsw/nuw(X, 1))
+      // or min(or_disjoint(X, 1), Y)
+      Value *AddOp;
+      bool IsOr = false;
+      if (match(M1LHS, m_c_Add(m_Specific(X), m_One())) && M1RHS == Y)
+        AddOp = M1LHS;
+      else if (match(M1RHS, m_c_Add(m_Specific(X), m_One())) && M1LHS == Y)
+        AddOp = M1RHS;
+      else if (match(M1LHS, m_c_DisjointOr(m_Specific(X), m_One())) && M1RHS == Y) {
+        AddOp = M1LHS;
+        IsOr = true;
+      } else if (match(M1RHS, m_c_DisjointOr(m_Specific(X), m_One())) && M1LHS == Y) {
+        AddOp = M1RHS;
+        IsOr = true;
+      } else
+        return nullptr;
+
+      // For or disjoint X, 1, no wrap check needed (equivalent to add nuw nsw X, 1)
+      if (!IsOr) {
+        auto *Add = dyn_cast<OverflowingBinaryOperator>(AddOp);
+        if (!Add)
+          return nullptr;
+
+        bool IsSigned = (IID == Intrinsic::smin || IID == Intrinsic::smax);
+        if ((IsSigned && !Add->hasNoSignedWrap()) ||
+            (!IsSigned && !Add->hasNoUnsignedWrap()))
+          return nullptr;
+      }
+
+      CmpInst::Predicate Pred;
+      if (IID == Intrinsic::smin)
+        Pred = ICmpInst::ICMP_SLT;
+      else if (IID == Intrinsic::smax)
+        Pred = ICmpInst::ICMP_SGT;
+      else if (IID == Intrinsic::umin)
+        Pred = ICmpInst::ICMP_ULT;
+      else if (IID == Intrinsic::umax)
+        Pred = ICmpInst::ICMP_UGT;
+      else
+        return nullptr;
+
+      Value *Cmp = Builder.CreateICmp(Pred, X, Y);
+      return SelectInst::Create(Cmp, ConstantInt::get(Ty, 1),
+                                ConstantInt::get(Ty, 0));
+    }
+  }
+
   return nullptr;
 }

